INSERT INTO reviews (order_id, restaurant_id, rating, comment, merchant_reply) SELECT id, restaurant_id, IF(id%2=0,5,4), CONCAT('Đồ ăn ngon! Đơn #',id), IF(id%3=0,'Cảm ơn bạn đã ủng hộ!',NULL) FROM orders WHERE status='COMPLETED' AND restaurant_id BETWEEN 1 AND 10;
